import React from "react";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "rain"; // Replace with real-time weather
  const isDaytime = false; // Replace with actual day/night logic

  return (
    <div
      className={`relative min-h-screen flex flex-col items-center justify-between overflow-hidden ${
        isDaytime ? "bg-white" : "bg-black"
      }`}
    >
      {/* Weather GIF Overlay */}
      <WeatherOverlay
        weatherCondition={weatherCondition}
        isDaytime={isDaytime}
      />

      {/* Header */}
      <div className="text-center py-8 z-10">
        <h1 className="text-4xl font-bold text-white drop-shadow-md">
          Today in <span className="text-purple-400">Atlanta</span>
        </h1>
        <p className="text-lg text-white/80 mt-1 capitalize drop-shadow-md">
          {weatherCondition}
        </p>
      </div>

      {/* Weather Cards */}
      <div className="flex-1 flex items-center justify-center px-6 z-10">
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6">
          {[
            { label: "Temperature", value: "36.2°C" },
            { label: "Humidity", value: "70%" },
            { label: "Wind Speed", value: "12 km/h" },
            { label: "UV Index", value: "5 (Moderate)" },
          ].map((card, idx) => (
            <div
              key={idx}
              className="transition-all duration-300 transform hover:scale-105 hover:shadow-2xl bg-white/10 backdrop-blur-xl rounded-2xl shadow-md p-6 ring-1 ring-white/20"
            >
              <p className="text-md font-medium text-white">{card.label}</p>
              <p className="text-3xl font-bold text-white mt-2">
                {card.value}
              </p>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom Nav - Glass Style */}
      <div className="h-20 w-full fixed bottom-0 left-0 bg-white/20 backdrop-blur-md border-t border-white/30 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-white hover:text-purple-400 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
